/**
 * Collage Prefix Usage Examples
 *
 * The COLLAGE_PREFIX constant identifies auto-generated collage images.
 * This allows you to easily filter and identify collages for batch operations.
 */

import { COLLAGE_PREFIX, generateCollage, blobToFile } from '../utils/collageGenerator';

// ============================================================================
// Example 1: Using the prefix constant in your own functions
// ============================================================================

function isAutoGeneratedCollage(filename) {
    return filename.startsWith(COLLAGE_PREFIX);
}

// Test usage:
console.log(isAutoGeneratedCollage('AUTO_COLLAGE_collage_1712957400000.png')); // true
console.log(isAutoGeneratedCollage('family_photo.jpg')); // false

// ============================================================================
// Example 2: Filter collages from a list of filenames
// ============================================================================

function filterCollagesFromImages(filenames) {
    return filenames.filter(filename => isAutoGeneratedCollage(filename));
}

const allFiles = [
    'AUTO_COLLAGE_collage_1234567890.png',
    'user_photo_1.jpg',
    'AUTO_COLLAGE_collage_1234567891.png',
    'user_photo_2.jpg',
];

const justCollages = filterCollagesFromImages(allFiles);
console.log(justCollages);
// Output: ['AUTO_COLLAGE_collage_1234567890.png', 'AUTO_COLLAGE_collage_1234567891.png']

// ============================================================================
// Example 3: Function to regenerate collages from Firebase Storage
// ============================================================================

async function regenerateCollagesFromStorage() {
    // Pseudocode - adapt to your Firebase setup
    const storage = getFirebaseStorage();
    const bucket = ref(storage, 'userPosts/');

    // List all files in storage
    const files = await listAll(bucket);

    // Filter to only auto-generated collages
    const existingCollages = files.items.filter(item =>
        item.name.startsWith(COLLAGE_PREFIX)
    );

    console.log(`Found ${existingCollages.length} existing collages`);

    // Now you can:
    // - Delete old collages and regenerate
    // - Update collages for existing posts
    // - Migrate to new collage format

    return existingCollages;
}

// ============================================================================
// Example 4: Firestore query to find posts with collages
// ============================================================================

async function findPostsWithCollages(db) {
    // Query for posts where first photo has the collage prefix
    // (Adapted based on your Firestore structure)

    const postsWithCollages = [];

    // This example assumes postPhotos is an array where [0] is the collage
    const querySnapshot = await getDocs(collection(db, 'userPosts'));

    querySnapshot.forEach((doc) => {
        const post = doc.data();
        if (post.postPhotos && post.postPhotos.length > 0) {
            // Check if first photo URL indicates a collage
            // (You'd need to check the filename from the URL)
            if (post.postPhotos[0].includes(COLLAGE_PREFIX)) {
                postsWithCollages.push({
                    postId: doc.id,
                    post: post,
                    collageUrl: post.postPhotos[0]
                });
            }
        }
    });

    return postsWithCollages;
}

