// ============================================================================
// Example 6: Collage statistics
// ============================================================================

function getCollageStats(filenames) {
    const stats = {
        totalFiles: filenames.length,
        collageFiles: 0,
        userFiles: 0,
        collagePercentage: 0,
    };

    filenames.forEach(filename => {
        if (isAutoGeneratedCollage(filename)) {
            stats.collageFiles++;
        } else {
            stats.userFiles++;
        }
    });

    stats.collagePercentage = (stats.collageFiles / stats.totalFiles * 100).toFixed(2);

    return stats;
}

const stats = getCollageStats(allFiles);
console.log(stats);
// Output: {
