//   collageFiles: 2,
//   userFiles: 2,
//   collagePercentage: '50.00'
// }

// ============================================================================
// Example 7: Validation function for Firebase Security Rules
// ============================================================================

// This could be used in Firebase security rules or validation logic:
//
// // In your Firestore/Storage rules, you might want to:
// // - Allow system to write files with COLLAGE_PREFIX
// // - Prevent users from creating files with this prefix
// // - Audit all collage creations
//
// Example JavaScript validation:

function isValidCollageUpload(filename, uploadedBySystem = false) {
    const hasPrefix = filename.startsWith(COLLAGE_PREFIX);

    // Allow only if uploaded by system (not user)
    if (hasPrefix && !uploadedBySystem) {
        return false; // User shouldn't create collage-prefixed files
    }

    // Allow user files (without prefix)
    if (!hasPrefix) {
        return true;
    }

    return uploadedBySystem;
}

console.log(isValidCollageUpload('AUTO_COLLAGE_photo.png', true));  // true (system upload)
console.log(isValidCollageUpload('AUTO_COLLAGE_photo.png', false)); // false (user attempt)
console.log(isValidCollageUpload('user_photo.jpg', false));         // true (normal user upload)

